#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        int blocks=1;
        for(int i=1;i<N;i++) if(s[i]!=s[i-1]) blocks++;
        if(blocks%3==0) printf("RAMADHIR\n");
        else printf("SAHID\n");
    }
    return 0;
}

